INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1261921','Прапор','(Марширує військо кроком молодим). Музика: Леопольд Ященко Слова: Дмитро Павличко. Виконує: Етнографічний хор Гомін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Марширує військо кроком молодим,
Синьо-жовтий прапор сяє понад ним.
Плаче сива жінка в глибині вікна,
За той прапор долю віддала вона.

За той рідний прапор, синій золотець,
Батько їй загинув, січовий стрілець.
За те сонце й небо, за той рідний стяг
Два сини-повстанці полягли в боях.

Марширує військо кроком молодим,
Синьо-жовтий прапор сяє понад ним.
Плаче сива жінка в глибині вікна,
А в сльозі відбилась вся Галичина.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1261921'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1261921','Прапор','Марширує військо кроком молодим,
