INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_126127','Вже два роки','(Не стій, коню, наді мною). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'За аудіозаписом концерту на фестивалі "Червона Рута" 1989 року.','Виконавець мені невідомий.','Вже два роки й дві неділі,
Як ми були на Вкраїні,
Як козака война вбила,      |(2)
Під явором положила.        |

Під явором зелененьким
Лежить козак молоденький,
Над ним коник зажурився,    |(2)
По коліна в землю вбився.   |

Не стій коню наді мною,
Бо я виджу щирість твою,
Іди, коню, до домочку,      |(2)
Неси мамі новиночку.        |

Іди, коню, до Дунаю,
Моя хата перша з краю,
З неї вийде стара баба,     |(2)
То є моя рідна мама.        |

Скажи, коню, що не вбили,
Скажи, коню, що женили:
Він взяв собі за жіночку    |(2)
В чистім полі могилочку.    |

Шукай, мамцю, докторика -
Молодого столярика,
Най ми він хату збудує,     |(2)
Чорнов фарбов помалює.      |

Без дверей та без віконця,
Щоб не було видно сонця,
Щоби люди не ходили         |(2)
Та в віконце не дивили.     |

Не стій, коню, наді мною,
Бо я виджу щирість твою,
Іди, коню, додомочку,       |(2)
Неси мамі новиночку.        |','[''pisni.org.ua'', ''cat:rekrutski'', ''Рекрутські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_126127'), datetime('now')),datetime('now'));
