INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1257127','В сорок другім році','Українська народна пісня. Виконує: Етнографічний хор Гомін','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В сорок другім році ми йдемо у бій
За Україну, за нарід свій!
Приспів:
Армія УПА у смертний бій вступає,
За Україну, за рівні права!
Ми, партизани, лавами рушаєм,
А за нами стане пробуджений народ!
Приспів.
Сурми вже заграли, в серці обізвались,
Вітер свободи наш стяг обвіва!
Приспів','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1257127'), datetime('now')),datetime('now'));
