INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1267303','А я чорнява','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Продав лісник зеленого дуба,
Купив мені золотого зуба.
Приспів:
А я чорнява, молода, кудрява, |
Цілу ніч не спала,            |
З лісником гуляла.            | (2)
Повів мене під білу березу,
Зробив з мене з п''яної тверезу.
Приспів.
Повів мене під сіна копичку,
Зробив з мене з дівки молодичку.
Приспів.
Повів мене в зелену цибулю,
Зробив мені на животі гулю.
Приспів.
Люлі-люлі, спи, моє дитятко,
Ти ж не знаєш, хто у тебе татко.
Приспів.','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1267303'), datetime('now')),datetime('now'));
