INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1270000','Весняні котики','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Сірі-сірі котики,
Сірі, наче дим,
Посідали котики
У рядок один.
Розпушились котики,
Вже їм не до сну -
Виглядають котики
Із кущів весну.

Приспів:
Котики, котики,
Хто вас так назвав?
Може кому, котики,
Ви сказали: "Няв!"
Може кому, котики,
Ви сказали: "Мур!"
Ну признайтесь котики:
Хто, коли це чув?

Пахнуть, пахнуть котики
Теплим вітерцем,
Пахнуть, пахнуть котики
Ніжним деревцем,
Пахнуть, пахнуть котики
Світлом і добром,
Пахнуть, пахнуть котики
Маминим теплом.

Приспів.

Няв! Мур!

Приспів. (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1270000'), datetime('now')),datetime('now'));
