INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1272707','Гімн України після вступу до ЄС','Музика: Антон Лебединець Слова: Володимир Остріжний','uk','ukraine_1991',NULL,NULL,NULL,'*Під жовто-блакитним – згадка про правильний порядок кольорів національного стягу українців.','Живи, Україно, прекрасна ти й сильна,
В Союзі Європи своє щастя знайшла.
Між рівних ти рівна, між вільних ти вільна,
Під сонцем Свободи мов квітка розцвіла.

Приспів:
Слава Європі, Союзові - слава,
Вітчизна хай славиться у вічності віків!
Живи, Україно, європейська державо,
В єдиній родині народів-братів!

Завжди в боротьбі нам за долю народну,
Наш друг і наш брат - Європи народ.
Нас гетьмани славні вели у походи,
Під жовто-блакитним* до ясних цих висот.

Приспів.

Ми працею славимо Державу могутню
І правду безсмертних величних ідей.
У світ демократії - вічне майбутнє,
Наш мудрий народ власним шляхом іде.

Приспів.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1272707'), datetime('now')),datetime('now'));
