INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_127000','Місто ангелів','Музика: Марія Бурмака Слова: Марія Бурмака. Виконує: Марія Бурмака','uk','ukraine_1991',NULL,NULL,'Аудіо-CD "Марія Бурмака. "№9" (2004)','Текст і акорди записано на слух з аудіо. Акорди подано спрощено. Оригінальна тональність: "F" (каподастр на I ладі). Пісня виконується "перебором". Для подальшого спрощення акорди "A7sus4" і "C#m6" можна не брати, а замість "E7sus4 E" можна брати грати "E". Деякі акорди: A7sus4 [x 0 x 0 3 0] C#m6 [4 x 3 4 3 x] E7sus4 [0 2 0 2 3 0] або [0 2 0 2 0 0] Підбір акордів: bohdanko (www.pisni.org.ua)','Вступ: A7sus4

Am
Місто ангелів і дощів
Dm
На казкові малюнки схоже.
Тільки ангелів - ні душі,
Am              E7sus4 E
а лиш просто так - перехожі.

Місто, що не чуже мені.
Золоте павутиння вулиць...
Все, здається, давно заснуло,
окрім світла в однім вікні.

Приспів:
Тільки раз і не більше,
G
знаю, не більше,
C          E7sus4 E
щоб забути назавжди.
Лиш на мить стану ближче,
G
Я стану ближче -
C          E7sus4 E
і не зможу вже піти.

Місто зустрічей і прощань...
і розбитих сердець, можливо.
Берег правий і берег лівий,
і всі шанси для сподівань.

Місто звуків і голосів.
По бруківці стікає тиша.
Все стає непомітно тихше,
І нечутне уже для всіх.

Приспів.

Ми стаємо серед дощів.
Ми цього зорепаду варті.
Що хотіти іще нам варто? -
лиш стояти на цій межі.

Місто пристрасті, і образ,
і примирень таких гарячих.
Ти, напевно, мене пробачиш -
я прощала тебе не раз.

Приспів...

Закінчення: Am','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_127000'), datetime('now')),datetime('now'));
