INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1272101','Добридень','Українська народна пісня. Виконує: Ігор Бущак','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Добридень, добридень, добридень скажу,
Як вранці чемненько до мами іду.
Тут палець, долоня, плече і рука,
Тут маю дві ніжки, а тут є п''ята.

Добридень, добридень, добридень скажу,
Як вранці чемненько до тата біжу.
Тут очка, тут личко, тут ніс, а тут губи,
Тут маю вушка, а тут білі зуби.

Добридень, добридень, добридень скажу,
Як вранці чемненько в садочок прийду,
Багато діточок, забавок у нас,
Веселою піснею вітаємо Вас!','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1272101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1272101','Добридень','Добридень, добридень, добридень скажу,
Як вранці чемненько до мами іду.
Тут палець, долоня, плече і рука,
Тут маю дві ніжки, а тут є п''ята.

Добридень, добридень, добридень скажу,
Як вранці чемненько до тата біжу.
Тут очка, тут личко, тут ніс, а тут губи,
Тут маю вушка, а тут білі зуби.

Добридень, добридень, добридень скажу,
Як вранці чемненько в садочок прийду,
Багато діточок, забавок у нас,
Веселою піснею вітаємо Вас!');
