INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1274220','Пісня для молодят','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Сьогодні ви життя з''єднали,
З''єднали руки і серця,
І на поріг сімейний стали,
Щоб разом йти у майбуття!
Тому дозвольте привітати
З єднанням в вашому житті,
Здоров''я, щастя побажати,
Щоб завжди були молоді!

Приспів:
Щоби розлуки ви не знали,
Лише в коханні ви живіть,
А все життя пісні співали
І в парі проживіть зі сто літ!

Нехай вас Бог благословляє,
Батьківські щирії слова,
Нехай вас горе обминає
І доля буде золота!
Щоб в мирі й злагоді прожити,
Не знали горя і біди,
Дітей щасливими зростити,
Онуки й правнуки були!

Приспів.    Фонограма-мінус','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1274220'), datetime('now')),datetime('now'));
