INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_127323','Як з Бережан до Кадри *','Музика: Роман Купчинський Слова: Роман Купчинський','uk','ukraine_1991',NULL,'2002',NULL,'текст пісні з CD "Йшли селом партизани" (с) 2002 ПТ "GroLis Records" (м. Тернопіль), http://www.grolis.com.ua) у виконанні Володимира Вермінського. За адресою: http://www.franko.lviv.ua/faculty/geology/phis_geo/fourman/Makivka-Kluch-2005/Makivka-songs.htm з посиланням на Похідний співаник Маківка, 2005 текст пісні дещо відрізняється: Як з Бережан до Кадри січовики манджали, То краялось серденько від горя і печалі. То краялось серденько в хорунжого Осипа, Коли з очей зникала та золотая Липа. То краялось серденько, не тихло й на хвилину, Бо в Бережанах кидав Коханую дівчину. Прощай, моє Олятко, дівчино чорнобрива, Нас нині розлучає та доля нещаслива. (2) Чи прийде час веселий, чи прийде зла година, Все тебе згадаю, що ти моя єдина.','Як з Бережан до Кадри січовики манджали,
То краялось серденько із горя і печалі. | (2)

То краялось серденько, не втихло ні на хвилину,
Як в Бережанах покинув коханую дівчину. | (2)

Прощай, моя дівчина, дівчино чорнобрива,
Нас нині розлучає ця доля нещаслива.    | (2)

Чи прийде час веселий, чи прийде злая година,
Я все тебе згадаю, що ти моя єдина.     | (2)

Як дівчина почула такі слова любові
То поцілуй зложила в устонька коральові. | (2)

Як з Бережан до Кадри січовики манджали,
То краялось серденько із горя і печалі. | (2)    Фонограма-мінус (mp3)','[''pisni.org.ua'', ''cat:dances'', ''cat:istorychni'', ''cat:strilecki'', ''cat:waltzes'', ''Пісні до танцю'', ''Історичні пісні'', ''Стрілецькі пісні'', ''Вальси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_127323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_127323','Як з Бережан до Кадри *','Як з Бережан до Кадри січовики манджали,
То краялось серденько із горя і печалі. | (2)

То краялось серденько, не втихло ні на хвилину,
Як в Бережанах покинув коханую дівчину. | (2)

Прощай, моя дівчина, дівчино чорнобрива,
Нас нині розлучає ця доля нещаслива.    | (2)

Чи прийде час веселий, чи прийде злая година,
Я все тебе згадаю, що ти моя єдина.     | (2)

Як дівчина почула такі слова любові
То поцілуй зложила в устонька коральові. | (2)

Як з Бережан до Кадри січовики манджали,
То краялось серденько із горя і печалі. | (2)    Фонограма-мінус (mp3)');
