INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1281426','Кольоровий світ','Музика: Марія Мазур Слова: Марія Мазур','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми візьмемо до рук кольорові фарби,
Розмалюємо світ у яскраві барви,
Сонце світить, а ми радісні й здорові:
Добрий ранок сонечко, світ такий чудовий! | (2)

Дощик ллє цілий день, стукає в віконце,
Не виходить з-за хмар золотаве сонце,
Ми візьмемо до рук фарби кольорові:
Добрий вечір дощику, світ такий чудовий!  | (2)

Темну ніч, сірий день гарно розфарбуєм,
Заспіваєм пісень, мрію намалюєм,
В небо кульки летять різнокольорові:
Добрий день країно, світ такий чудовий!   | (2)

Ми візьмемо до рук кольорові фарби,
Розмалюємо світ у яскраві барви,
Сонце світить, а ми радісні й здорові:
Добрий ранок сонечко, світ такий чудовий! | (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1281426'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1281426','Кольоровий світ','Ми візьмемо до рук кольорові фарби,
