INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1275127','Новорічне диво','Музика: Василь Ткач Слова: Василь Ткач. Виконує: Vroda','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Рік Старий спішить додому,
Він дарує "старт" Новому,
Передавши кращі відчуття!
В Новім році нові сили,
Щоб добро разом творили,
Щоби були нові відкриття!
І з натхненням до вершини
Ми пройшли прості стежини,
Року Новому дамо життя!
Ми відкриємо всі двері
До сердець і до оселі,
Хай кохання янголи летять!

Приспів:
І в тебе, і в мене
Є мрія здійснена:
В Новий рік нова історія!
Для тебе й для мене
Кохання шалене,
В Новорічне диво вірю я!

Без жалю і без вагання,
Повні віри й сподівання,
Скажемо потрібні всім слова:
В Новім році краще буде,
Вірим в новорічне чудо,
Ця пора багата на дива!

Приспів. (2)','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1275127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1275127','Новорічне диво','Рік Старий спішить додому,
Він дарує "старт" Новому,
Передавши кращі відчуття!
В Новім році нові сили,
Щоб добро разом творили,
Щоби були нові відкриття!
І з натхненням до вершини
Ми пройшли прості стежини,
Року Новому дамо життя!
Ми відкриємо всі двері
До сердець і до оселі,
Хай кохання янголи летять!

Приспів:
І в тебе, і в мене
Є мрія здійснена:
В Новий рік нова історія!
Для тебе й для мене
Кохання шалене,
В Новорічне диво вірю я!

Без жалю і без вагання,
Повні віри й сподівання,
Скажемо потрібні всім слова:
В Новім році краще буде,
Вірим в новорічне чудо,
Ця пора багата на дива!

Приспів. (2)');
