INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1276921','Двоє на майдані','Слова: Анатолій Миколайчук','uk','ukraine_1991',NULL,'2014','Інформаційний бюлетень ІКААПУ Інформ №5 (278) 2014 рік.',NULL,'Не шукайте таємного змісту,
Просто доля, мов карта лягла:
Двоє хлопців зібралися в місто,
Двоє хлопців з одного села.

Незіпсовані, сильні, красиві,
Їм обом ще нема й двадцяти,
Їхні мами ще зовсім не сиві.
Їх просили себе берегти...

І шляхи їх згубились в тумані,
Різні долі, як різні пісні...
Хто ж міг думати, що - на Майдані,
Знов зустрінуться раптом вони.

Як від повені вруниться річка,
Так зіткнулись - очима й чолом.
Та в одного в руках єврострічка,
А на іншому - чорний шолом...','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1276921'), datetime('now')),datetime('now'));
