INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1278404','Троє поросят','Слова: Юрій Винничук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Троє поросят
Пішли собі до Хряка,
Троє поросят
Сказали грізно: "Кака!"

Троє поросят
Потисли йому ручку,
А Хряк сказав: "Давай
Зіграєм у трясучку!

Кому впаде "орел",
Кому судилась "рішка",
Хто з-поміж вас козел,
Хто слон, а хто з вас пішка".

Троє поросят
Верталися від Хряка.
Троє поросят
Зітхали сумно: "Кака".

З наперсточником грати
Забракло їм таланту:
Монета тричі впала
Й на диво тричі кантом.','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1278404'), datetime('now')),datetime('now'));
