INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_128808','Ой у саду ружа посаджена','Українська народна пісня. Виконує: Юлія Дошна, Бурдон','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой у саду ружа посаджена,
Каже хлопець, же я не червена.
Та най каже, а я не журюся,
Кому мила, тому сподоблюся.

Не кладу на личко червенило,
Мене в поли сонце припалило,
Припалило спереду і збоку,
А я собі дівчина нівроку.

Мене мати в плахті колихала,
При кирниці кождий день купала.
Ой купала та й забула втерти,
Буду файна до самої смерти.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_128808'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_128808','Ой у саду ружа посаджена','Ой у саду ружа посаджена,
Каже хлопець, же я не червена.
Та най каже, а я не журюся,
Кому мила, тому сподоблюся.

Не кладу на личко червенило,
Мене в поли сонце припалило,
Припалило спереду і збоку,
А я собі дівчина нівроку.

Мене мати в плахті колихала,
При кирниці кождий день купала.
Ой купала та й забула втерти,
Буду файна до самої смерти.');
