INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1288921','Нашим пацанам','Музика: Гайдамаки Слова: Олександр Ярмола. Виконує: Гайдамаки','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Крилаті слова злетіли у світ,
Сказав їх один позитивний чувак,
Почувши їх, прозріли всі:
Війна прийшла під кожен дах.
Уходили хлопці на війну,
За ними наступні збиралися.
Усі обіцяли вернутися,
Але не всі верталися.

Приспів:
Усе туди, на фронт -
Нашим пацанам!
Усе туди, на фронт -
Нашим пацанам!
Усе туди, на фронт -
Нашим пацанам!
Поможи їм, Бог,
Захисти їх там,
Де стріляють "Гради"...

Там поруч з героями Майдану
Воюють Беркуту бійці,
Ветерани Афганістану
І молоді гвардійці.
Усі чекають відмашки, рвуться в бій,
Піднявши прапор державний свій,
Але немає наказу,
І знову вертатися на базу.

Приспів.

На фронті серед сепаратистів
Боєць "Оплоту", з яким ти бився.
Ти маєш щастя його зустріти
І все йому пояснити.
Мирним людям не зрозуміти -
Війну не можна так просто спинити,
Нам випала наша доля,
І ми з тим будемо жити.

Приспів.
Усе туди, на фронт -
Нашим пацанам!
Поможи їм, Бог...','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1288921'), datetime('now')),datetime('now'));
