INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1281725','Зайшло сонечко','Музика: Ніна Матвієнко Слова: Ніна Матвієнко. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Зайшло сонечко,
