INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_129404','Коли хмеліє в думках голова','(Про неї). Музика: Ярослав Юрчишин Слова: Ярослав Юрчишин. Виконує: Ярослав Юрчишин','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Коли хмеліє в думках голова
Не забувай, щаслювцю, миті цеї
Тоді у ній народяться слова
До неї однієї.

Коли у ватрі холод дотліва
І ніжно хилять голови лілеї
Навічно викарбуються слова
До неї однієї

Коли втікаєш з потягу життя
Який посіли блазні і лакеї
Не згадуй надаремо ти ім''я
Тікаючи не варто й думати про неї.

А час минає. Більше вороття
Назад не буде. Бриз цілує реї.
Реальні на планеті почуття
Все решта - тлін. Крім неї однієї','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_129404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_129404','Коли хмеліє в думках голова','Коли хмеліє в думках голова
Не забувай, щаслювцю, миті цеї
