INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1294606','Пролісок','Музика: Анна Олєйнікова Слова: Наталія Іванова. Виконує: Софія Комарова','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'В зимовій хатинці на білій перинці
Пролісок маленький очка розкриває,
Весну зустрічає, сам себе питає:

Чом джерельце дзюркотить, весело співає?
Чом у синій висоті пташечка літає? -
Бо весна знов прийшла, знову завітала,
Щиро сонечко її в небі зустрічало.

Виходить з хатинки, стає він навшпиньки -
Пролісок біленький радо розквітає,
Весну зустрічає, сонечко вітає.

Бо джерельце дзюркотить, весело співає, |
А у синій висоті пташечка літає!        |
То весна знов прийшла, знову завітала,  |
Щиро сонечко її в небі зустрічало.      | (2)

Щиро сонечко її в небі зустрічало!..','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1294606'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1294606','Пролісок','В зимовій хатинці на білій перинці
Пролісок маленький очка розкриває,
Весну зустрічає, сам себе питає:

