INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_130024','Марія-Діва днесь породила','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Марія-Діва днесь породила
Цвіт пахучий, цвіт розкішний.
Його здавна світ весь грішний,
Здавна пожадав.          | (2)

У Вифлеємі зацвів красою
Цвіт той райський, Божий, ясний,
І рознісся запах красний
По всій землиці.         | (2)

Заблисла зоря, несесь по світі
Вість весела, вістка мила,
Що всіх вбогих звеселила:
Христос приходить.       | (2)

А за зорею, та за красою
Вже йдуть люди, йдуть веселі,
У Вифлеємські оселі
Несуть поклони.          | (2)

Несуть поклони з всіх кінців світа:
Несуть в дарі, що хто може,
Ісус-квітка, Дитя Боже,
Благослови всіх.         | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_130024'), datetime('now')),datetime('now'));
