INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1295505','Христос воскрес','Музика: Тарас Курчик Слова: Тарас Курчик. Виконує: Тарас Курчик','uk','ukraine_1991',NULL,NULL,NULL,NULL,'День новий настає,
Силу й радість дає,
З Днем народження, День.
Світло нищить пітьму
І ми знаєм тому,
І ми знаєм тому,
За велінням із небес
Сталось чудо із чудес -

Приспів:
Христос Воскрес,
Христос Воскрес!
Христос Воскрес,
Христос Воскрес!

В Нім складне і просте,
Він у всьому росте,
Богу дякуєм ми:
За щасливе буття,
За любов до життя,
Від весни до весни.
За велінням із небес
Сталось чудо із чудес!

Приспів. (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:voskresni'', ''Церковні пісні'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1295505'), datetime('now')),datetime('now'));
