INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1304529','Помолюся тихо','Виконує: Віктор Покидюк','uk','ukraine_1991',NULL,NULL,'http://muzofon.com/search/',NULL,'До Тебе, Боже, руки я здіймаю,
Твоє в молитві згадую Ім''я,
Бо в серці я любов безмірну маю       |
І світлою стає душа моя!              | (2)

Приспів:
Помолюся тихо словом нелукавим,       |
Щоб по світу лихо більше не блукало.  |
Стану на коліна до Христа промовлю,   |
Щоб для України дав щасливу долю!     | (2)

І в цьому незбагненному єднанні
Для всіх хай буде істина проста,
Останній час це буде не останній      |
Для того, хто повірив у Христа!       | (2)

Приспів.

Ти мій Спаситель, Ти моя надія,
Що завтра день не згасне у пітьмі.
З тобою буду я по справжньому радіти, |
Ти - мій Господь, а я навіки Твій!    | (2)

Приспів.

Стану на коліна, до Христа промовлю,
Щоб для України дав щасливу долю!    Фонограма мінус (mp3)  (','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1304529'), datetime('now')),datetime('now'));
