INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1301202','Весняна хмаринка','Музика: Анна Олєйнікова Слова: Наталя Іванова. Виконує: Вікторія Попова','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Жила-була у небі
Білесенька хмаринка,
Блакитно-синє небо
Було її хатинка.
Літала в піднебессі
І бавилась із сонцем,
Хмаринка виглядала
З небесного віконця.

Приспів:
Земле моя гарна,
В білому вбранні.
Розквітаєш, земле,
Цвітом навесні.
Всі радіють діти,
Разом з ними я,
Бо весняні квіти -
Усмішка твоя.

І зрозуміла хмарка,
Що квітка-веселинка
Біленька і грайлива,
Немов її світлинка.
Вони співали разом
І бавились із сонцем,
А сонце посміхалось
З небесного віконця.

Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1301202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1301202','Весняна хмаринка','Жила-була у небі
