INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1303323','Казав мені в лісі сатана','Слова: Тарас-Чача Крушельницький','uk','ukr_ssr_1919_1991',NULL,'1929','аудіозапис','Жартівлива пісня ІІІ. Куріня ст. пл. "Лісові Чорти" з 1929 р. Під мелодію стрілецької пісні.','Казав мені в лісі сатана,
Що на світі лиш одна біда:
Жий, жий, уживай,                  |
Пластунок не зачіпай!              | (2)

"Ті, що греблі рвуть" -
Страшні пані,
Чорта не схотять, ах ні!
Жий, жий, уживай,                  |
"Тих, що греблі рвуть" не зачіпай! | (2)

В "Санітарок" серце хоч горить,
То вже "Чорноморець" в нім сидить!
Жий, жий, уживай,                  |
"Санітарок" не зачіпай!            | (2)

"Ластівки", хоч мають очка два,
То "Озони" впали в обидва!
Жий, жий, уживай,                  |
"Ластівок" не зачіпай!             | (2)

Ти, чортяко бідний, не журись,
В целібат Мурлики запишись!
Жий, жий, уживай,                  |
Пластунок не зачипай!              | (2)','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1303323'), datetime('now')),datetime('now'));
