INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_13024','Не пора, не пора','Музика: Денис Січинський Слова: Іван Франко. Виконує: Соколи, Іван Мацялко','uk','ukraine_1991',NULL,NULL,'Сьпіваник Українських Січових Стрільців. Відень, 1918.','Акорди (варіант 1) надав Ярослав Юрчишин. Останні 2 рядки - двічі.','Не пора, на пора, не пора
Москалеви й ляхови служить!
Довершилась Україні кривда стара -
Нам пора для України жить!
Не пора, не пора, не пора
За невигласків лить свою кров
І любити царя, що наш люд обдира, -
Для України наша любов!
Не пора, не пора, не пора
В рідну хату вносити роздор!
Най пропаде незгоди проклята мара!
Під Украйни єднаймось прапор!
Бо пора це великая єсть:
У завзятій, важкій боротьбі
Ми поляжем, щоб волю і славу і честь,
Рідний краю, здобути тобі.
Акорди (варіант 1):
Не пора, нe пора, не пора
Москалеви й ляхови служить!
Довершилась Україні кривда стара -
Нам пора для України жить!','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_13024'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_13024','Не пора, не пора','Не пора, на пора, не пора
Москалеви й ляхови служить!
Довершилась Україні кривда стара -
