INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1316828','Гімн Висоцька','Музика: Микола Буткевич Слова: П. Паливода','uk','ukraine_1991',NULL,NULL,'вікіпедія',NULL,'Віками вмиваєшся в славній Горині,
У щедрім, веселім, поліськім краю.
Ти, крапле барвиста, в святій Україні,
Шаную тебе я, як волю свою!

Приспів:
Ти, Висоцьку мій зореносний,
І радість, і щастя моє!
Тут батьків поріг непорослий:
І перше кохання моє.

Ти — острів маленький у повені пишній,
Де в хвилях гойдаються завжди човни,
Ростуть у садах твоїх яблуні й вишні,
В молочному цвіті красують вони.

Приспів.

Твій обрій втопає у луках зелених,
Де в лозах співають пісні солов''ї,
А в небі курличчя журавок веселих,
Закоханих в наші озерні краї.

Приспів.

Віками вмиваєшся в славній Горині
У щедрім, веселім, поліськім краю.
Із давніх-давен і до світлого нині
Тебе ми шануєм, як волю свою!

Приспів.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1316828'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1316828','Гімн Висоцька','Віками вмиваєшся в славній Горині,
