INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1304808','З Новим роком!','Музика: Павло Табаков Слова: Павло Табаков. Виконує: Павло Табаков','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
З Новим роком! З Новим роком!
З Новим роком! З Новим роком!

Іще не приніс подарунки тобі
Миколай,
Все рівно Новий рік
Ти з нами разом зустрічай!
Настрою святкового
Ти повні кишені збираєш,
І Новий Рік із нами,
Із нами Новий Рік зустрічай!

Приспів.

Як сніг мете на вулиці
Ти телевізор свій вимикаєш,
Тебе чекають рідні і друзі,
Просто часу не гаєш,
Коли всі феєрверки злетять угору
Просто згадаєш,
Що було доброго у цьому році
І Новий зустрічай!

Приспів.

Обійми всіх, кого любиш,
Міцно так пригорни,
Ну, а дітям хай насняться
Кольоровії сни,
Загадай, щоб ми в любові
В цьому світі жили
І добро, добро і радість
В Новий рік принесли!

Приспів.

З Новим роком!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1304808'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1304808','З Новим роком!','Приспів:
