INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1317426','Білосніжка','Музика: Анна Кривута Слова: Анна Кривута. Виконує: Анна Кривута','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тільки зійшов на небо
Місяць ясний,
Знову мені наснився
Сон чарівний:
Маленька хатка стоїть,
Навколо темні ліси -
Там Білосніжка живе,
А з нею - гноми-брати.
Дівчинка їм смачний
Готує обід,
А Білосніжку брати
Оберігають від бід,
Та через жовті поля,
Через зелені ліси
До Білосніжки спішить
Сміливий принц на коні!

Приспів:
Біло-біло-білосніжка,
Дівчинка з моєї книжки!
І весела, і слухняна,
З добрим серцем полум''яним!
Біло-біло-білосніжка,
Ніжні ручки, білі ніжки,
А душею добра й чиста,
Ллється пісня, як намисто!

Серед полів,
Серед зелених дібров.
Птахом злетить у небо
Світла любов.
Хай не засне в палацах
Мачуха зла,
Завдати лиха комусь тепер
Не в силі вона!..
В казках завжди
Перемагає добро,
Нехай же серед людей
Завжди панує воно!
І серед жовтих полів,
Серед зелених дібров
Своїм теплом зігріває
Всіх чарівна любов!

Приспів.

Речитатив:
Але світанок зійшов
На балкон,
Глянув у вікна -
Закінчився сон.
Брати у кімнаті
Тихенько дрімали,
Я двері відкрила
І раптом впізнала:
Це гноми казкові
Хропіли у ліжку,
Виходить, що я -
Чарівна Білосніжка!

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1317426'), datetime('now')),datetime('now'));
