INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_130909','А в тій Хаті як у Раю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа (Коляда). Рай розвився Господь звеселився. Сад садили Сад поливали. Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Бог, Різдво Світа, Дідух і Лицарі. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Порівняння: Українці й Уралалтайці. Стежки до листків про Українські традиції.','А в тій Хаті як у Раю
