INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1326725','Ніхто, крім нас','Українська народна пісня','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Повітря скрипить на зубах, наче порох,
І кулі свистять біля скронь.
За спинами мирних ховається ворог,
І ми зупиняєм вогонь!
Не вірячи в карту з відсутністю Крима,
Ми бачимо сни у вогні...
Ковтаєм свинець за Донбас, за країну |
На чорній брехливій війні.           | (2)

Приспів:
Земля горить від крові і від поту,
Ридають матері у мирний час.
Ніхто крім нас не зробить цю роботу, |
Ніхто крім нас, ніхто крім нас!      | (2)

Розірвані нерви, придумані вісті,
Кипучий і праведний гнів...
І їде хлопчина - вантаж номер двісті
Від кулі колишніх братів.
Та нас не поставить ніхто на коліна -
Доводили хлопці не раз.
Є сила і правда, і є Україна,        |
А значить, і небо за нас!            | (2)

Приспів.','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1326725'), datetime('now')),datetime('now'));
