INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1329426','Ой, на горі два дубочки, третій - зелененький','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1937',NULL,'Уснословесний жанр козацька пісня Місце побутування с. Лімна, Лімнянська сільрада, Турківський район, Львівська область Респонденти Кіра Катерина Василівна, 1937 р.н., Васильків Настя Миколаївна, 1929 р.н., Понейко Феня Миколаївна, 1931 р.н. Збирачі Артем''як Мар''яна, Папіш Марія, Довгань Оксана','Ой, на горі два дубочки,
Третій - зелененький.
Лежить, лежить у шпиталю
Козак молоденький.

Лежить, лежить у шпиталю,
Думає вмирати.
Просить своїх товаришів:
"Дайте мамі знати".

Просить своїх товаришів:
"Дайте мамі знати,
Що я лежу у шпиталю,
Думаю вмирати".

Приїхала стара мати,
Як голуб сивенька,
Пригорнула, притулила
До свого серденька.

Пригорнула, притулила,
Ще й поцілувала.
Ой, сину, ж мій ріднесенький,
То''м тя не спізнала.

А як ти ня, моя мати,
Маєш спізнавати,
Як я лежу у шпиталю,
Думаю вмирати.

То няй мене не ховають
Ні попи, ні дяки,
А най мене поховають
Вкраїнські козаки.

Бо ті попи і ті дяки
На заплаті б''ються,
А вкраїнські козаченьки
Сльозами вмиють.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1329426'), datetime('now')),datetime('now'));
