INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1315024','Плесь, не стій','Музика: Л. Миргородська Слова: Ж. Калюжна','uk','ukraine_1991',NULL,NULL,'http://www.minus.lviv.ua/minus/artist/%D0%9D%D0%B5%D0%B2%D1%96%D0 %B 4%D0%BE%D0%BC%D0%B8%D0%B9/rec/261','Дитяча пісенька. Українські пісні для дітей.','Підемо у двір гуляти,
Тра-ля-ля-ля-ля-ля.
Зимову пісню вітати,
Тра-ля-ля-ля-ля-ля.

Приспів:
Плесь-плесь-плесь, не стій, |
Швидше рученята грій.       |
Туп-туп-туп Мороз -         |
Наші ніжки не морозь.       | (2)

Ми доріжки промели,
Тра-ля-ля-ля-ля-ля.
Купки снігу намели,
Тра-ля-ля-ля-ля-ля.

Приспів.

З снігу зліпимо сніжки,
Тра-ля-ля-ля-ля-ля.
Люблять зиму малюки,
Тра-ля-ля-ля-ля-ля.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1315024'), datetime('now')),datetime('now'));
