INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1337808','Йде весна!','Музика: Ярослава Притула (Slavia) Слова: Ярослава Притула (Slavia). Виконує: Ярослава Притула','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Покотились води з горів,
Зашуміли річки в долі,
Журавлі летять додому,
Земле, оживай.
Ліс ожив зазеленівся,
Соловейко пробудився,
Та й виводить свої трелі -
Це моя весна!

Ой, мамо, мамо, мамо, мамо, |
Йде весна!..                | (4)

Дівка квітів назбирала,
У віночок посплітала,
Милому подарувала
Цвіт красу весни.
Набирайся земле сили
Щщоби ми ще краще жили,
Нене моя, Україно -
Мій тобі уклін!

Ой, мамо, мамо, мамо, мамо, |
Йде весна!..                | (6)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1337808'), datetime('now')),datetime('now'));
