INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1355828','Над колискою сина','Музика: Євген Кухарець Слова: Микола Негода. Виконує: Черкаський народний хор','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Всміхається мені маля,
До мене тягне рученята,
І серце радо звеселя,
І сонця повна хата!..
За всіх,
За всіх на світі матерів
Щаслива я і вдячна я,
Усім, хто в полум''ї згорів,
Щоб усміхалося маля!

Всміхається мені маля,
Іще не відає нічого,
Ракетами страхіття зле
Націлилось на нього...
За всіх,
За всіх на світі матерів
Тривога й страх мене пройма,
Як чую гуркоти громів,
Чи не поглине сонце тьма...

Всміхається мені дитя,
Біля грудей його зігрію.
Несу у світ нове життя,
Любов свою й надію!
За всіх,
За всіх на світі матерів
Звертаюсь я, благаю я,
Не дайте в полум''ї згоріть!
О, захистіть моє дитя!
За всіх,
За всіх на світі матерів
Звертаюсь я, благаю я,
Молю, ви землю збережіть,
Щоб усміхалося маля!','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1355828'), datetime('now')),datetime('now'));
