INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_135725','Добрі мі є, добрі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Туристський пісенник "Там на Лемковині помедже горами". - Літо, 1981.','Лемківська пісня зі Словаччини Діалектизми: ани - ані; водит ся - ведеться; десят - десять; добрі - добре; дяка - охота, вподоба; єдну - одну: єдну-єм - одну я; жена - дружина; знам - знаю; зохабив - лишив, покинув; мам - маю; лем - тільки; премилена - наймиліша, дуже люба; тівко - скільки; тота - та, ота.','Добрі мі є, добрі, добрі ся мі водит,
Ея-гоя, єдну-єм зохабив, десят за мнов ходит. |(2)

Про мене дівчата зачали ся бити,
Ея-гоя, а я і сам не знам, котру мам любити.  |(2)

Бийте лем ся, бийте, тівко вам до смаку,
Ея-гоя, бо вы ани єдна не на мою дяку!        |(2)

Тота буде моя премилена жена,
Ея-гоя, котра буде в селі перша выхвалена!    |(2)
Акорди:
Добрі мі є, добрі, добрі ся мі водит,
Ея-гоя, єдну-єм зохабив, десят за мнов ходит. |(2)','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_135725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_135725','Добрі мі є, добрі','Добрі мі є, добрі, добрі ся мі водит,
