INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_135404','Павочка xодить Пір’ячко губить','Українська народна пісня. Виконує: Надія Купчинська','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Рокове Коло. Десь узялася Молода Дівчина. Павочка xодить Пір''ячко губить. Ой в Саду Саду Пава ходила Ой Горі Горі Павоньки ходять Ой у Садоньку Павоньки ходять Ой у Садоньку Павоньки ходять (2) Павочка xодить Пір''ячко губить Павочка xодить Пір''ячко ронить Павочка ходя Пірьєчко роня По Горі Горі Пави ходили Танцї виводе все ў перед ходе. Йшла Дівчина на Гаївку Пір''ячко збирала. Ой не годен пан Каньовський мене цілувати. Там гуляла Бондарівна як Пишная Пава. А з Полянойки до Царинойки. Стріцовим Пірком заволочена. Сподівайтеся Вінця до свого Гуменця. Замітайте Двори застелайте Столи Вербний тиждень і мотив передвеликодньої шутки у Святім Вечері. Між мітологійними мотивами Свят-Вечера й Святої Вечері відбиває своєю невиразністю і на перший погляд недоцільністю мотив шутки передвеликодньої, приложеної до Святоріздвяних містерій. Це в річи пальмова галузка полудневого Сходу з християнських містерій Цвітної Неділі, а на Україні вербова (євова) весняна галузка з першими весняними бростиками, також з християнським мотивом. (Прим.: Шутка — вербова гілка, вкрита пухнастими Котиками (Котики – цвіт Верби), Словник Грінченка) Але по правді — це мотив прастарий і світовий, поширений від непам''ятних передхристиянських часів у цілім Полудневім Сході, особливо у Індійців та Іранців, звідки, мабуть, поширився по цілій Европі. Він і досі як весняна зелена галузка є символом надходячого Весняного Відродження. Вважається за маґічний орудник, побуджаючий Весняний розвиток у природі, відновлення життя в світі звіриннім і рослиннім та охороняючий від елементарних нещасть. Нею вдаряють корови при першім вигоні худоби на зелену пашу (на Україні на св. Юра); її втикують по нивах на полі і т.і. (Не я б''ю Верба б''є.) Юр, народний покровитель худібки: два Свята. // Українські та Іранські рівнобіжності. // Юр і народне шанування Змія та Місяця. Про символічне її значення є гадки мітологів і етнологів поділені. Kuhn вважає її за символ Вогню в природі. L. v. Schroeder — за символ Весняного Сонця як джерела Вогню і животворного тепла в природі. Kuhn, пояснюючи обряд вдарювання худоби шуткою при Веснянім вигоні на пашу, наводить рядки з Ріґ-Веди (IV, 27, ст. 4), де розказується про це, як Птиця, що несла на землю божеський напиток Somâ, зронила Перо і оце Перо стало Деревом palâça або çami. Kuhn пояснює цей міт так, що перо — це властиво вогонь, а вдаряюча зелена галузка — це також вогонь; стадо, що йде на зелену пашу, — це символ хмар, а галузка — символ Весняної блискавки. Пояснення A. Kuhn-a, — хоч не умотивоване мітологійно, — є близьке до правди, як це покажеться при ближчім розгляненні Української ідеології в мотиві шутки; а Індійський міт про Птицю, що вронила перо, з якого виросло дерево, послужить як раз до пояснення правильного розвитку цієї ідеології. (Порівняти з містеріями світотворення, — Іскра впала Озеро стало, — Купелі Бога і Плачу Сокола/Господа.) Павочка xодить Пір''ячко губить Йшла Дівчина на Гаївку Пір''ячко збирала Приложення Великодньої шутки до Українських Святоріздвяних містерій є зовсім логічним по Староукраїнській ідеології Свят Різдва і Великодня, бо оба Свята проголошують Нове життя: перше є Святом Різдва Світа, а друге є Святом майбутнього Відродження Світа. Українська Весняна Великодня шутка має своє ідейне угрунтовання в Святі Різдва Світа і може стати поясненням всесвітніх містерій з Весняною галузкою та їх первісного мотиву. Бо, на мою думку, як Великодня, так і Різдвяна шутка — це символ Райського Дерева або Прадерева. Про нього співають усі Колядки і Щедрівки і воно є не лишень символом перших проявів рослинного життя на землі, але і символом первісної творчої і безупинно дійової Сили в природі. Може бути, що і по думці народу Українського цією первісною Силою був творчий Вогонь, бо в Українських Святоріздвяних містеріях бачимо також шанування Вогню. Але всі Українські Колядки і Щедрівки дають доказ, що цією містичною Силою, хочби і Вогнем, вважає нарід Астральну силу Небесної Трійці, в якій перворядне місце займає Місяць. Він є чинником рослинного життя і плодоносности земного Світа, а заразом чинником Небесного Вогню. (Прим. Кс.С.: Уособленням небесного Вогню, а заразом родючої Сили природи є в Щедрівках Ілля, а він без всякого сумніву є Українським символом Місяця. Покликуюся на те, що було вже сказане на цю тему на попередніх сторінках. У Щедрівках, які співають про виправу Білого Молодця, про Дівчину між Місячними символами, що цю постать окружують, є й блискавка та грім, а оці явища приписує нарід Іллі. Мітологійне значення тих символів можна зрозуміти щойно в повнім їх зв''язку.) Райське Дерево, — найпопулярніша ідея Колядок та Щедрівок, — є тільки символом Місяця і живоносної Сили природи. В пізнішім розділі про Українське Прадерево будуть наведені Колядки й Щедрівки, з яких увидимо виразно, що Великодня і Різдвяна шутка є символами Місячними, бо таким символом є там Прадерево; в Колядках також найдуться аналогії до Індійського мітичного дерева çami, які стануть заразом поясненням для цього Індійського міту. В кожнім разі буде можна ствердити, що Український мотив шутки відбиває від світових своєю ясною характеристикою і доцільністю; що — як Прадерево — має призвання принести людям та їх худобині обнову життя. Будьте великі як Верба а здорові як Вода а багаті як Земля! Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Ой стояла Липка Тонка та Висока Коляда і Великдень: Різдво і Відродження Світа. Еротичні містерії, тиждень від Катерини 7.12 до Калети — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Світові аналогії. Відтворення містерій Сотворення Світа. Ритуальний танець як вираз реліґійної екстази. Рокове Коло. Стежки до листків про Українські традиції.','Павочка xодить Пір''ячко губить

Приспів:
Святий Вечір Добрим Людям

За Нею ходить Красна Дівонька
Пір''я збирає в Рукав xоває
З Рукава бере на Лавку кладе
З Лавоньки бере Віночки плете
А звивши Вінок понесла в Танок','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''Колядки'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_135404'), datetime('now')),datetime('now'));
